mapper.sql:
tenant_id = #{tenantId} AND deleted = false
AND route_code = #{q.routeCode}
AND section_code ILIKE concat('%', #{q.sectionCode}, '%')
AND section_name ILIKE concat('%', #{q.sectionName}, '%')
AND direction = #{q.direction}
AND adcode = #{q.adcode}
AND start_stake <= #{q.stake} AND end_stake >= #{q.stake}

mapper.select:
SELECT id FROM road_section
WHERE tenant_id=#{tenantId} AND route_code=#{routeCode} AND direction=#{direction}
  AND start_stake=#{startStake} AND end_stake=#{endStake} AND deleted=false LIMIT 1
